    from itertools import combinations
    import numpy as np

    # Check if all points are 4D
    for point in points:
        if len(point) != 4:
            raise ValueError("All points must be 4-dimensional.")

    points = np.array(points)
    n = len(points)

    # Edge cases
    if n <= 1:
        return points.tolist()
    if n == 2:
        return points.tolist()

    # Function to check if a point is inside the hyperplane formed by other points
    def is_inside_hyperplane(point, hull_points):
        A = np.array(hull_points)
        b = np.append(np.zeros(len(hull_points) - 1), 1)
        try:
            coeffs = np.linalg.solve(A.T, b)
            return np.all(coeffs >= 0) and np.isclose(np.sum(coeffs), 1)
        except np.linalg.LinAlgError:
            return False

    # Generate all combinations of points to form hyperplanes
    hull_points = set()
    for r in range(1, n + 1):
        for combo in combinations(points, r):
            if len(combo) < 4:
                continue
            if not is_inside_hyperplane(combo[0], combo[1:]):
                hull_points.update(combo)

    return np.array(list(hull_points)).tolist()

def convex_hull_4d(points):
    from itertools import combinations
    import numpy as np

    # Check if all points are 4D
    for point in points:
        if len(point) != 4:
            raise ValueError("All points must be 4-dimensional.")

    num_points = len(points)

    # Edge cases
    if num_points < 5:
        return points  # Convex hull is the set of points itself if less than 5 points

    points = np.array(points)

    # Function to check if a point is inside the hyperplane defined by the other points
    def is_inside_hyperplane(point, hull_points):
        A = np.array(hull_points)
        b = np.array(point)
        return np.linalg.matrix_rank(A) == np.linalg.matrix_rank(np.column_stack((A, b)))

    # Generate all combinations of points to form hyperplanes
    hull_points = set()
    for comb in combinations(range(num_points), 5):
        hyperplane_points = points[list(comb)]
        for i in range(num_points):
            if i not in comb:
                if not is_inside_hyperplane(points[i], hyperplane_points):
                    hull_points.update(hyperplane_points)
                    break

    return list(hull_points)

