    if n == 2:
        return points.tolist()

    # Function to check if a point is inside the hyperplane defined by the simplex
    def is_inside_simplex(simplex, point):
        simplex = np.array(simplex)
        A = np.vstack((simplex.T, np.ones(simplex.shape[0])))
        b = np.hstack((point, 1))
        return np.linalg.matrix_rank(A) == np.linalg.matrix_rank(np.vstack((simplex.T, b)))

    # Generate all combinations of points to form simplices
    hull_points = set()
    for simplex in combinations(points, 5):
        simplex = np.array(simplex)
        # Check if there are points outside the simplex
        outside_points = [p for p in points if not is_inside_simplex(simplex, p)]
        if len(outside_points) == 0:
            hull_points.update(simplex)

    return list(hull_points)

